<h1 class="h5 mb-3">Logs y webhooks Flow</h1>
<form class="row g-2 mb-3" method="GET" action="<?= e(url('/admin/flow/logs')) ?>"><div class="col-md-3"><select name="empresa_id" class="form-select"><option value="">Todas empresas</option><?php foreach($empresas as $e): ?><option value="<?= (int)$e['id'] ?>" <?= (string)$filtros['empresa_id']===(string)$e['id']?'selected':'' ?>><?= e($e['nombre_comercial']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><input type="date" class="form-control" name="desde" value="<?= e($filtros['desde']) ?>"></div><div class="col-md-2"><input type="date" class="form-control" name="hasta" value="<?= e($filtros['hasta']) ?>"></div><div class="col-md-2"><input type="text" class="form-control" name="tipo" value="<?= e($filtros['tipo']) ?>" placeholder="tipo"></div><div class="col-md-3"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form>
<div class="row g-3"><div class="col-lg-7"><div class="card"><div class="card-header">Logs integración</div><div class="table-responsive"><table class="table table-sm mb-0"><thead><tr><th>Fecha</th><th>Empresa</th><th>Tipo</th><th>Nivel</th><th>Mensaje</th><th>Ref.</th></tr></thead><tbody><?php foreach($logs as $l): ?><tr><td><?= e($l['fecha_creacion']) ?></td><td><?= e($l['empresa'] ?? '-') ?></td><td><?= e($l['tipo']) ?></td><td><?= e($l['nivel']) ?></td><td><?= e($l['mensaje']) ?></td><td><?= e($l['referencia'] ?? '-') ?></td></tr><?php endforeach; ?></tbody></table></div></div></div><div class="col-lg-5"><div class="card"><div class="card-header">Webhooks</div><div class="table-responsive"><table class="table table-sm mb-0"><thead><tr><th>Fecha</th><th>Tipo</th><th>Token</th><th>Resultado</th></tr></thead><tbody><?php foreach($webhooks as $w): ?><tr><td><?= e($w['fecha_creacion']) ?></td><td><?= e($w['tipo_evento']) ?></td><td><?= e($w['token'] ?? '-') ?></td><td><?= e($w['resultado'] ?? ($w['procesado'] ? 'ok' : 'pendiente')) ?></td></tr><?php endforeach; ?></tbody></table></div></div></div></div>
